#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int start;
    int end;
} Interval;

int cmp(const void *p1, const void *p2) {
    const Interval *i1 = (const Interval *)p1;
    const Interval *i2 = (const Interval *)p2;
    if (i1->end != i2->end) return i1->end - i2->end;
    return i1->start - i2->start;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Interval *arr = (Interval *)malloc(N * sizeof(Interval));
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &arr[i].start, &arr[i].end);
        }
        qsort(arr, N, sizeof(Interval), cmp);
        int last = -1;
        int ans = 0;
        for (int i = 0; i < N; ++i) {
            if (arr[i].start > last) {
                last = arr[i].end;
                ++ans;
            }
        }
        printf("%d\n", ans);
        free(arr);
    }
    return 0;
}

